+    fn test_complex64_tensor_log1p_preserves_dtype_and_shape() {
+        let input = Value::Tensor(
+            TensorValue::new(
+                DType::Complex64,
+                Shape { dims: vec![2] },
+                vec![
+                    Literal::from_complex64(0.0, 0.0),
